  if(looksLikeGibberishInput(raw) || looksLikeGenericCommandOnly(raw) || looksLikeBroadSubject(raw) || looksLikeMultiTargetContent(raw)) return OUTPUT_FORMAT_BASKETS.INPUT_GUIDANCE;
