  if(/^(?:which|list|name|what\s+(?:countries|planets|ingredients|types|kinds|examples|items))\b/i.test(raw)) return OUTPUT_FORMAT_BASKETS.LIST;
  if(/^(?:why|how\s+(?:does|do|did|can|could|should|is|are)|what\s+is\s+the\s+difference|what\s+causes|how\s+are|how\s+is)\b/i.test(raw)) return OUTPUT_FORMAT_BASKETS.WHY_HOW;
  if(/^where\b/i.test(raw)) return OUTPUT_FORMAT_BASKETS.LOCATION;
  if(/^what\s+(?:happens|would happen)\b/i.test(raw)) return OUTPUT_FORMAT_BASKETS.PRACTICAL_GUIDANCE;
  if(/^what\s+(?:does|do|is|are|was|were|causes|makes)\b/i.test(raw)) return OUTPUT_FORMAT_BASKETS.DIRECT_ANSWER;
  if(/^(?:is|are|was|were)\b[^?]{1,180}\bor\b[^?]{1,100}\??$/i.test(raw)) return OUTPUT_FORMAT_BASKETS.DIRECT_ANSWER;
