  if(/\b(?:today|yesterday|current|currently|latest|recent|new|news|202[4-9]|going|announced|removed?|removing|launched|recalled|approved|banned|lawsuit|court|election|poll|stock|price|company|product|brand|mars|candy|dye)\b/i.test(raw)) return true;
