function stableFormatNumber(value){
  const n=Number(value);
  if(!Number.isFinite(n)) return '';
  if(Math.abs(n-Math.round(n))<1e-10) return String(Math.round(n));
  return String(Number(n.toFixed(10)));
}
function stableExtractNumberList(value){
  const raw=clean(value);
  const segment=(raw.match(/\b(?:of|values?|numbers?|data(?:\s+set)?)\b([\s\S]*)/i)||['',raw])[1] || raw;
  return (segment.match(/-?\d+(?:\.\d+)?/g)||[]).map(Number).filter(Number.isFinite);
}
function stableSourceBasisForCategory(category){
  const c=clean(category).toLowerCase();
  if(/math|statistic|logic|geometry/.test(c)) return 'Standard mathematics and logic';
  if(/biology|genetic|medical|health/.test(c)) return 'Established biology and health references';
  if(/engineering|material|physics/.test(c)) return 'Established engineering and physical-science references';
  if(/chem/.test(c)) return 'Established chemistry references';
  if(/astronom|space/.test(c)) return 'Established astronomy references';
  if(/geograph|earth science|geolog/.test(c)) return 'Established geography and Earth-science references';
  if(/history|government|culture/.test(c)) return 'Established historical and cultural references';
  if(/language|grammar|acronym/.test(c)) return 'Established language references';
  return 'Established general-reference knowledge';
}
