  const fromMoon=/\b(?:from|on)\s+(?:the\s+)?moon\b|\bmoon\b.*\b(?:naked\s+eye|unaided\s+eye)\b/i.test(text);
  const fromSpace=/\bfrom\s+(?:outer\s+)?space\b|\bfrom\s+(?:low\s+earth\s+)?orbit\b|\blow\s+earth\s+orbit\b/i.test(text);
  const nakedEye=/\b(?:naked\s+eye|unaided\s+eye|without\s+(?:a\s+)?telescope|without\s+optical\s+aid)\b/i.test(text);
