function normalizeBirdSleepFlightQuestionText(value){
  let s=clean(value);
  if(!s) return '';
  // Common speech/typing slip: "sleep why flying" or "sleep why they fly" when the intended phrase is "sleep while flying".
  s=s.replace(/\bsleep\s+why\s+(?:they\s+)?fly(?:ing)?\b/gi,'sleep while flying');
  s=s.replace(/\bsleep\s+why\s+(?:they\s+)?are\s+flying\b/gi,'sleep while flying');
  s=s.replace(/\bsleep\s+why\s+(?:they\s+)?(?:are\s+)?in\s+flight\b/gi,'sleep while flying');
  return clean(s);
}
function looksLikeBirdSleepFlightContextQuestion(value){
  const s=normalizeBirdSleepFlightQuestionText(value);
  if(!s || /^https?:\/\//i.test(s)) return false;
  const birdSignal=/\b(?:birds?|frigatebirds?|swifts?|migratory\s+birds?)\b/i.test(s);
  const sleepSignal=/\bsleep(?:s|ing)?\b/i.test(s);
  const flightSignal=/(?:\b(?:while|whilst|during)\s+(?:flying|flight)\b|\bin\s+flight\b)/i.test(s);
  return !!(birdSignal && sleepSignal && flightSignal);
}
function looksLikeBirdSleepFlightListQuestion(value){
  const s=normalizeBirdSleepFlightQuestionText(value);
  if(!looksLikeBirdSleepFlightContextQuestion(s)) return false;
  return /^(?:what|which|list|name|tell\s+me|show\s+me|give\s+me)\b/i.test(s) || /\bwhat\s+birds?\b/i.test(s);
}


