  if(/^(?:[a-z]{1,3}|\d{1,3})\1{2,}$/i.test(t)) return true;
  if(t.length>=6 && /(.)\1{3,}/i.test(t)) return true;
  if(t.length>=7 && !/[aeiouy]/i.test(t)) return true;
