    const unique=new Set(low.split('')).size;
    if(vowels/low.length<0.20 && unique<=Math.max(5,Math.ceil(low.length*0.55))) return true;
    if(digits>=2 && !/[aeiouy]{2}/i.test(low) && unique<=Math.max(5,Math.ceil(low.length*0.65))) return true;
