  add('known-entity-only-protection',100,looksLikeKnownEntityOnly(raw),'entity-only input protected as broad subject');
  add('semantic-short-input-protection',95,semantic && gibTokens.length===0 && !looksLikeAlternatingNonsense(raw) && !looksLikeRepeatedTokenNonsense(raw) && !looksLikeMixedSymbolKeyboardNoise(raw),'meaningful short input protected');
