  add('repeated-token-nonsense',98,looksLikeRepeatedTokenNonsense(raw) && !semantic,'repeated gibberish token pattern');
  add('mixed-symbol-keyboard-noise',97,looksLikeMixedSymbolKeyboardNoise(raw) && !semantic,'symbol/keyboard noise pattern');
