  add('low-vowel-compact-string',94,compact.length>=6 && !/[aeiouy]/i.test(compact) && !semantic,'compact string has no vowels');
  add('all-alpha-tokens-gibberish',93,alphaTokens.length && gibTokens.length===alphaTokens.length,'all alpha tokens are gibberish-like');
  add('majority-alpha-tokens-gibberish',91,alphaTokens.length>=2 && gibTokens.length/alphaTokens.length>=0.67,'majority of alpha tokens are gibberish-like');
  add('short-low-semantic-with-gibberish-token',89,words.length<=4 && compact.length>=6 && gibTokens.length>=1 && !semantic,'short input contains gibberish token');
  add('short-symbol-or-digit-noise',88,words.length<=3 && compact.length>=8 && symbolNoise+digitCount>=2 && !semantic,'short input contains symbol/digit noise');
  add('low-vowel-letter-ratio',87,letters>=8 && vowels/Math.max(1,letters)<0.18 && !semantic,'low vowel ratio');
  let lowUnique=false;
  let unique=0;
  if(compact.length>=10 && /^[a-z0-9]+$/i.test(compact) && !semantic){
    unique=new Set(compact.toLowerCase().split('')).size;
    lowUnique=unique<=Math.max(5,Math.ceil(compact.length*0.55));
  }
  add('low-unique-character-density',86,lowUnique,'low unique character density');
  const hitRules=rules.filter(r=>r.hit);
  const invalidRules=hitRules.filter(r=>!/protection|empty-input/.test(r.name));
  const protectionRules=hitRules.filter(r=>/protection/.test(r.name));
  const winner=(invalidRules[0]||protectionRules[0]||hitRules[0]||{name:'none',score:0,reason:'no rule fired'});
  const rejected=rules.filter(r=>!r.hit).map(r=>r.name+'('+r.score+')').slice(0,10).join(',') || 'none';
