  const letters=(raw.match(/[a-z]/gi)||[]).length;
  const vowels=(raw.match(/[aeiouy]/gi)||[]).length;
  const alphaTokens=words.filter(w=>/[a-z]/i.test(w));
  const gibTokens=alphaTokens.filter(looksLikeGibberishToken);
  const symbolNoise=(raw.match(/[^a-z0-9\s]/gi)||[]).length;
  const digitCount=(raw.match(/[0-9]/g)||[]).length;
  if(looksLikeSemanticShortInput(raw) && gibTokens.length===0 && !looksLikeAlternatingNonsense(raw) && !looksLikeRepeatedTokenNonsense(raw) && !looksLikeMixedSymbolKeyboardNoise(raw)) return false;
