  if(alphaTokens.length && gibTokens.length===alphaTokens.length) return true;
  if(alphaTokens.length>=2 && gibTokens.length/alphaTokens.length>=0.67) return true;
  if(words.length<=4 && compact.length>=6 && gibTokens.length>=1 && !looksLikeSemanticShortInput(raw)) return true;
  if(words.length<=3 && compact.length>=8 && symbolNoise+digitCount>=2 && !looksLikeSemanticShortInput(raw)) return true;
