function classificationRuleMatrix(input){
  const raw=clean(input);
  const rules=[
    'CLAIM','QUESTION','DOCUMENT','MEDIA','SPECIFIC_CONTENT_URL','PORTAL_URL','MULTI_TARGET_CONTENT','BROAD_SUBJECT','WORD_OR_PHRASE','INVALID_INPUT','INVALID_REQUEST'
  ];
  const candidates=[];
  function add(type,score,reason){ candidates.push({type:type,score:score,reason:reason}); }
  if(!raw){ add('INVALID_REQUEST',100,'empty input'); }
  if(looksLikeCurrentReligiousBeliefPublicSourceQuestion(raw)) add('QUESTION',99,'current religious public-belief source routing');
  if(looksLikeBroadEntityOverviewRequest(raw)) add('BROAD_SUBJECT',100,'broad entity overview request detected');
  if(entityMeaningIdentificationProfile(raw)) add('QUESTION',100,'entity meaning identification gate-order repair');
  if(looksLikeInformationalRequestInput(raw)) add('QUESTION',99,'informational request accepted');
  if(isBiologyAnimalClassificationFactualInput(raw)) add(isQuestionInputText(raw)?'QUESTION':'CLAIM',97,'biology-animal-classification factual routing');
  if(isBiologyAnimalCapabilityFactualInput(raw)) add(isQuestionInputText(raw)?'QUESTION':'CLAIM',98,'biology-animal-capability factual routing');
  if(isHealthMedicalFactualInput(raw)) add(isQuestionInputText(raw)?'QUESTION':'CLAIM',97,'health-medical factual routing');
  if(isFinanceGovernmentInstitutionalFactualInput(raw)) add(isQuestionInputText(raw)?'QUESTION':'CLAIM',96,'finance-government-institutional factual routing');
  if(generalStableFactRecoverySupport(raw)) add(isQuestionInputText(raw)?'QUESTION':'CLAIM',98,'general stable fact recovery routing');
  if(looksLikeStableOddCommonFactInput(raw)) add(isQuestionInputText(raw)?'QUESTION':'CLAIM',98,'stable odd/common factual routing');
  if(looksLikeHowToInstructionRequest(raw) && !looksLikeInformationalRequestInput(raw)) add('INVALID_REQUEST',99,'how-to request requires a specific verifiable claim instead');
  if(looksLikeValidShortFactualClaimOrQuestionInput(raw)) add(normalizeFactualYesNoQuestionToClaim(raw)||/[?]$/.test(raw)?'QUESTION':'CLAIM',98,'question-and-short-claim-regression-repair');
  if(looksLikeStandardFactualClaimInput(raw) || looksLikeGeneralDeclarativeFactualClaimInput(raw)) add('CLAIM',92,'standard/general factual claim protection');
  if(looksLikeKnownVerifiableFaithClaimInput(raw)) add('CLAIM',94,'faith claim priority before word/phrase meaning preview');
  if(looksLikeGibberishInput(raw) && !looksLikeInformationalRequestInput(raw)) add('INVALID_INPUT',99,'gibberish or non-analyzable text');
  if(looksLikeKnownEntityOnly(raw)) add('BROAD_SUBJECT',100,'recognized entity-only input requires a specific page or claim');
  if(looksLikeGenericCommandOnly(raw)) add('INVALID_REQUEST',97,'generic command without analyzable content');
  if(looksLikeBroadSubject(raw)) add('BROAD_SUBJECT',93,'broad subject without claim/question/page detail');
  if(wordMeaningPreviewInput(raw)) add('WORD_OR_PHRASE',86,'single word or short phrase can show meaning but needs context before verification');
  if(looksLikeMultiTargetContent(raw)) add('MULTI_TARGET_CONTENT',98,'archive/listing/category/collection or multi-section/multi-topic input requires user-selected target');
  if(/^https?:\/\//i.test(raw)){
    const host=hostnameOfUrl(raw);
    const path=pathnameOfUrl(raw);
    if(looksLikeNonVideoWebpageForVideoAuthInput(raw)) add('NON_VIDEO_WEBPAGE',99,'webpage is not a specific submitted video for authenticity analysis');
    if(looksLikeMediaUrl(raw)) add('MEDIA',96,'media URL pattern');
    if(/\.(pdf|docx?|xlsx?|pptx?|txt|csv)(?:[?#].*)?$/i.test(raw)) add('DOCUMENT',95,'document file URL');
    if(looksLikePortalUrl(raw)) add('PORTAL_URL',94,'homepage/portal path');
    if(!looksLikePortalUrl(raw) && !looksLikeMediaUrl(raw) && !looksLikeMultiTargetContent(raw)) add('SPECIFIC_CONTENT_URL',88,'URL with content path');
    if(host) add('SPECIFIC_CONTENT_URL',30,'URL host present: '+host);
  }
  if(looksLikeMediaUrl(raw)) add('MEDIA',80,'media/transcript indicator');
  if(looksLikeDocumentInput(raw)) add('DOCUMENT',78,'document length or document extension');
  if(/[?]$/.test(raw) || /^(is|are|was|were|did|does|do|can|could|will|would|has|have|should|what|when|where|why|how|give\s+me|show\s+me|tell\s+me|list|provide|explain|summarize|define|describe)\b/i.test(raw)) add('QUESTION',75,'question/informational request starter');
  if(/^(what is true|is this true|is it true|analyze this|check this|verify this|fact check this|fact-check this|tell me the truth|is the government lying|are they lying|is this accurate|is this factual)\??$/i.test(raw)) add('INVALID_REQUEST',90,'vague request phrase');
  if(/^(analyze|verify|check|fact check|fact-check)\s+(nasa|cdc|ssa|irs|white house|government|this site|this website|the internet|news|media|politics|health|science)$/i.test(raw)) add('INVALID_REQUEST',88,'broad command without subject detail');
  const words=raw.split(/\s+/).filter(Boolean).length;
  if(words>0 && words<3 && !/^https?:\/\//i.test(raw)) add('INVALID_REQUEST',85,'too few words');
  if(/\b(?:is|are|was|were|has|have|had|will|causes|caused|shows|proves|announced|reported|claims|says|said|found|signed|issued|released|landed|rose|exists|contains|supports|requires|strikes?|struck|orbits?|orbited|orbiting|revolves?|revolved|revolving|rotates?|rotated|rotating|spins?)\b/i.test(raw) && words>=3) add('CLAIM',70,'declarative/claim verb signal');
  if(words>=6 && !/[?]$/.test(raw) && !/^https?:\/\//i.test(raw)) add('CLAIM',55,'sufficient claim-like text length');
  const sorted=candidates.sort((a,b)=>b.score-a.score);
  const r=classifyRequest(input);
  const winner=r.type;
  const matchTypes=[...new Set(sorted.filter(c=>c.score>=50).map(c=>c.type))];
  return {rules:rules,candidates:sorted.slice(0,8),winner:winner,matches:matchTypes};
}
function classificationValidationDetails(input){
  const raw=clean(input);
  const isUrl=/^https?:\/\//i.test(raw);
  const host=isUrl?hostnameOfUrl(raw):'';
  const path=isUrl?pathnameOfUrl(raw):'';
  const pathDepth=urlPathDepth(raw);
  const words=raw.split(/\s+/).filter(Boolean).length;
  const sentences=splitSentences(raw).length;
  const features=[
    'is_url='+(isUrl?'yes':'no'),
    'host='+(host||'none'),
    'path='+(path||'none'),
    'path_depth='+pathDepth,
    'word_count='+words,
    'sentence_count='+sentences,
    'question_signal='+((/[?]$/.test(raw)||/^(is|are|was|were|did|does|do|can|could|will|would|has|have|should|what|when|where|why|how|give\s+me|show\s+me|tell\s+me|list|provide|explain|summarize|define|describe)\b/i.test(raw))?'yes':'no'),
    'media_signal='+(looksLikeMediaUrl(raw)?'yes':'no'),
    'document_signal='+(looksLikeDocumentInput(raw)?'yes':'no'),
    'portal_signal='+(looksLikePortalUrl(raw)?'yes':'no')
  ];
  const m=classificationRuleMatrix(input);
  const winner=m.winner;
  const winningCandidate=m.candidates.find(c=>c.type===winner);
  const winnerScore=winningCandidate?winningCandidate.score:0;
  const next=m.candidates.find(c=>c.type!==winner);
  const nextScore=next?next.score:0;
  const rejected=m.candidates.filter(c=>c.type!==winner).map(c=>c.type+' rejected: '+c.score+' vs '+winnerScore+'; reason='+c.reason).join(' ; ') || 'none';
  return {
    features:features.join('; '),
    rejected:rejected,
    margin:winner+' '+winnerScore+' vs '+(next?next.type: 'none')+' '+nextScore+' = '+(winnerScore-nextScore)
  };
}

function guidanceByTargetType(needed){
  if(needed==='PAGE'){
    return {
      options:'Provide one specific article/report/action/document/page URL; or provide one direct video URL; or provide one verifiable claim from the listing.',
      examples:'https://www.whitehouse.gov/briefing-room/statements-releases/2026/06/01/example-specific-page/'
    };
  }
  if(needed==='CLAIM'){
    return {
      options:'Provide one specific verifiable claim.',
      examples:'Example: Enter one specific factual claim.'
    };
  }
  if(needed==='SECTION'){
    return {
      options:'Provide one specific section heading, page range, excerpt, or claim from the document.',
      examples:'Analyze the report section titled “Economic Impact,” pages 12-14.'
    };
  }
  if(needed==='TIMESTAMP'){
    return {
      options:'Provide one specific timestamp, chapter, topic, or quoted claim from the media item.',
      examples:'Analyze the claim made at 12:35 in the video.'
    };
  }
  if(needed==='TOPIC'){
    return {
      options:'Provide one specific topic, question, or claim.',
      examples:'Example: Ask one specific factual question.'
    };
  }
  return {
    options:'Enter a specific claim, question, article/report/action/document/page URL, direct video URL, document text, transcript, section, or timestamp.',
    examples:'Example: Enter one specific factual claim or question.'
  };
}
function acceptabilityGuidanceDetails(input){
  const r=classifyRequest(input);
  if(r.acceptability==='ACCEPTABLE'){
    return {
      guidance:'Input is specific enough for analysis.',
      options:'Proceed with normal analysis.',
      examples:'none needed'
    };
  }
  const needed=targetTypeNeededForInput(input);
  const tailored=guidanceByTargetType(needed);
  if(r.type==='NON_VIDEO_WEBPAGE'){
    return {
      guidance:'This input is a webpage, not a specific submitted video for authenticity analysis.',
      options:'Submit a specific video URL, video file, transcript, title/description, or claim from the video.',
      examples:'https://www.youtube.com/watch?v=VIDEO_ID | URL: https://www.youtube.com/watch?v=VIDEO_ID Title: video title Description: video description Transcript: video transcript'
    };
  }
  if(r.type==='MULTI_TARGET_CONTENT'){
    return {
      guidance:'This input contains or points to multiple possible targets. R1 analyzes one specific target at a time.',
      options:tailored.options,
      examples:tailored.examples
    };
  }
  if(r.type==='PORTAL_URL'){
    return {
      guidance:'This is a homepage containing many different topics. For a meaningful accuracy analysis, provide a specific page, claim, question, document, or direct video URL.',
      options:tailored.options,
      examples:tailored.examples
    };
  }
  if(r.type==='BROAD_SUBJECT'){
    return {
      guidance:'This is a broad subject, not a specific verification target. Provide a specific page, claim, question, document, or direct video URL.',
      options:tailored.options,
      examples:tailored.examples
    };
  }
  if(r.type==='WORD_OR_PHRASE'){
    return {
      guidance:'A word meaning can be shown, but AIVerify needs a specific claim, question, page, source, or context before verification.',
      options:'Turn the word or phrase into one specific claim or question; or provide the page, source, sentence, or context where it is used.',
      examples:'Example: What does twilight mean in this sentence? | Example: Twilight happens after sunset. | Example: Does A1C measure average blood sugar?'
    };
  }
  if(r.type==='INVALID_INPUT'){
    return {
      guidance:'This input cannot be analyzed because it does not contain a recognizable claim, question, document, media item, or URL.',
      options:'Enter one specific factual claim, factual question, page URL, document text, media item, transcript, section, or timestamp.',
      examples:'Example: Enter one specific factual claim or question.'
    };
  }
  if(r.type==='INVALID_REQUEST'){
    return {
      guidance:'The request is too vague or incomplete for reliable accuracy analysis.',
      options:tailored.options,
      examples:tailored.examples
    };
  }
  if(r.specificity==='LOW'){
    return {
      guidance:'The request needs more detail before a high-confidence accuracy analysis can be made.',
      options:tailored.options,
      examples:tailored.examples
    };
  }
  return {
    guidance:'The request may need clarification before analysis.',
    options:tailored.options,
    examples:tailored.examples
  };
}


function targetTypeNeededForInput(input){
  const r=classifyRequest(input);
  if(r.type==='NON_VIDEO_WEBPAGE') return 'VIDEO';
  if(r.type==='MULTI_TARGET_CONTENT'){
    const reason=multiTargetDetectionDetails(input).reason;
    if(/category|tag|search|archive|listing|collection|page/i.test(reason)) return 'PAGE';
    if(/playlist|channel|chaptered|video|media|transcript|timestamp/i.test(reason)) return 'TIMESTAMP';
    if(/report|document|multi-section|section/i.test(reason)) return 'SECTION';
    return 'CLAIM';
  }
  if(r.type==='PORTAL_URL') return 'PAGE';
  if(r.type==='BROAD_SUBJECT') return 'CLAIM';
  if(r.type==='WORD_OR_PHRASE') return 'CONTEXT';
  if(r.type==='QUESTION' && r.acceptability!=='ACCEPTABLE') return 'TOPIC';
  if(r.acceptability!=='ACCEPTABLE') return 'CLAIM';
  return 'NONE';
}
function targetSelectionHintForInput(input){
  const needed=targetTypeNeededForInput(input);
  if(needed==='PAGE') return 'provide-one-specific-page-url-or-one-verifiable-claim-from-the-listing';
  if(needed==='CLAIM') return 'provide-one-specific-verifiable-claim';
  if(needed==='TOPIC') return 'narrow-the-question-to-one-specific-topic-or-claim';
  if(needed==='SECTION') return 'select-one-report-section-heading-page-range-or-quoted-claim';
  if(needed==='TIMESTAMP') return 'provide-one-video-timestamp-chapter-topic-or-quoted-claim';
  return 'not-needed';
}

function requestAuditLines(input){
  const r=classifyRequest(input);
  const m=classificationRuleMatrix(input);
  const v=classificationValidationDetails(input);
  const isMultiTarget=r.type==='MULTI_TARGET_CONTENT' || looksLikeMultiTargetContent(input);
  const multi=multiTargetDetectionDetails(input);
  const cand=m.candidates.map(c=>c.type+'('+c.score+': '+c.reason+')').join(' ; ') || 'none';
  const classificationEvidence=isMultiTarget ? 'multi-target-content-detected; see MULTI_TARGET_REASON' : r.evidence;
  const rejected=isMultiTarget ? 'suppressed-duplicate-multi-target-candidate-details' : v.rejected;
  const features=isMultiTarget ? 'multi-target specificity gate; URL/content features preserved' : v.features;
  return [
    'INPUT_CLASSIFICATION_STAGE_REACHED: true',
    'CLASSIFICATION_RULES_AVAILABLE: '+m.rules.join(', '),
    'CLASSIFICATION_RULE_MATCHES: '+(m.matches.length?m.matches.join(', '):'none'),
    'CLASSIFICATION_CANDIDATES: '+cand,
    'CLASSIFICATION_WINNER: '+m.winner,
    'CLASSIFICATION_VALIDATION_STAGE_REACHED: true',
    'CLASSIFICATION_INPUT_FEATURES: '+features,
    'CLASSIFICATION_REJECTED_CANDIDATES: '+rejected,
    'CLASSIFICATION_WIN_MARGIN: '+v.margin,
    'REQUEST_TYPE: '+r.type,
    'REQUEST_SPECIFICITY: '+r.specificity,
    'REQUEST_ACCEPTABILITY: '+r.acceptability,
    'REQUEST_GATE_STATE: '+gateStateForRequest(r),
    'CURL_ROUTE_VERIFY: type='+r.type+'; status='+gateStateForRequest(r)+'; acceptability='+r.acceptability,
    'URL_ROUTING_DECISION: '+(/^https?:\/\//i.test(clean(input))?urlRoutingDecision(input):'not-url'),
    'URL_PATH_DEPTH: '+(/^https?:\/\//i.test(clean(input))?urlPathDepth(input):'na'),
    'PORTAL_MATCH_REASON: '+(/^https?:\/\//i.test(clean(input))?portalMatchReason(input):'not-url'),
    'LISTING_PAGE_OVERRIDE: '+(looksLikeWhiteHouseListingPage(input)?'true':'false'),
    'MULTI_TARGET_CONTENT_DETECTED: '+(isMultiTarget?'true':'false'),
    'MULTI_TARGET_REASON: '+multi.reason,
    'SPECIFICITY_ENFORCEMENT_ACTION: '+(isMultiTarget?'gate-before-analysis-user-selects-target':'none'),
    'TARGET_TYPE_NEEDED: '+targetTypeNeededForInput(input),
    'TARGET_SELECTION_HINT: '+targetSelectionHintForInput(input),
    gibberishClassificationAudit(input),
    broadSubjectProtectionAudit(input),
    'CLASSIFICATION_CONFIDENCE_GUARD: no routing change unless INVALID_INPUT confidence exceeds existing winner by at least 10 points',
    'ACCEPTABILITY_REASON: '+r.reason,
    'ACCEPTABILITY_GUIDANCE: '+acceptabilityGuidanceDetails(input).guidance,
    'ACCEPTABILITY_OPTIONS: '+acceptabilityGuidanceDetails(input).options,
    'ACCEPTABILITY_EXAMPLE_INPUTS: '+acceptabilityGuidanceDetails(input).examples,
    'REQUEST_TYPE_CONFIDENCE: '+r.confidence,
    'REQUEST_CLASSIFICATION_EVIDENCE: '+classificationEvidence
  ];
}

