  if(targetExpansionContext[low]) return targetExpansionContext[low];
  if(initiativeContext[low]) return initiativeContext[low];
  if(/^(Office of|Council of|Department of|Office on|Office for)\b/i.test(p)) return 'The White House homepage includes the '+p+' as a linked institutional office.';
