    if(/^policies\s+have\s+secured\s+the\s+southern\s+border/i.test(p)) p='Policies have secured the southern border, reducing illegal entries.';
    if(/^record[- ]setting\s+capital\s+expenditures/i.test(p)) p='Record-setting capital expenditures are cited as driving productivity and technological advancement.';
    if(/tax reforms/i.test(p) && /deregulation/i.test(p) && /private[- ]sector investments/i.test(p)) p='Tax reforms and deregulation fueled private-sector investments.';
    if(!/[.!?]$/.test(p)) p+='.';
