  const rationale=/\b(?:can help|help protect|in line with American values|most effective and moral|history of the world|American values|responsibly accelerate|peacetime and on the battlefield|greatest|moral military|warfighters|prosperity|leadership|global leader|mission|vision|goal|aim|benefit|enable precise operations|minimize harm|technical overmatch)\b/i.test(cd);
