function completeSentenceAuditCandidates(text, route){
  const out=[];
  splitSentences(String(text||'')).forEach(sentence=>{
    let p=clean(sentence);
    if(!p) return;
    if(route==='url-institutional'){
      p=p.replace(/^At home,?\s+/i,'');
      if(/^decisive\s+policies\s+have\s+/i.test(p)) p=p.replace(/^decisive\s+/i,'');
      if(/^marked\s+by\s+/i.test(p)) p='The United States is described as having '+p.replace(/^marked\s+by\s+/i,'')+'.';
      if(/^record[- ]setting\s+capital\s+expenditures\s+driving/i.test(p)) p='Record-setting capital expenditures are cited as driving productivity and technological advancement.';
      if(/^tax reforms,?\s+deregulation/i.test(p)) p='Tax reforms and deregulation fueled private-sector investments.';
      if(/^policies\s+have\s+secured\s+the\s+southern\s+border/i.test(p)) p='Policies have secured the southern border, reducing illegal entries.';
    }
    p=normalizeClaimCandidate(p);
    if(!p || p.split(/\s+/).length<7) return;
    if(isInstitutionalTitleOnlyClaim(p, route)) return;
    if(isFactualAssertion(p) || (route==='url-institutional' && hasConcreteVerificationSignal(p))){
      out.push(p);
    }
  });
  const seen=new Set();
  return out.filter(x=>{const k=claimRootKey(x).slice(0,180); if(!k||seen.has(k)) return false; seen.add(k); return true;});
}


function articleClaimExtractionQualityScore(raw, claim, display, route){
  const r=clean(raw), c=clean(claim), d=clean(display);
  const x=(r+' '+c+' '+d);
  let score=0;
  const words=c.split(/\s+/).filter(Boolean).length;
  const complete=hasCompleteSubjectVerbStructure(c) || hasCompleteSubjectVerbStructure(d);
  const concrete=hasConcreteVerificationSignal(c) || hasConcreteVerificationSignal(d);
  const concreteAction=/\b(?:signed|issued|ordered|directed|requires|required|announced|released|published|created|expanded|established|implemented|authorized|prohibited|instructed|amended|revoked|rescinded|assigned|designated|terminated|superseded)\b/i.test(x);
  const namedAuthority=/\b(?:executive order|memorandum|proclamation|directive|policy|law|regulation|rule|National Security Presidential Memorandum|NSPM[-–]?\d+|Office of|Department of|Secretary|Administrator|Director|agency heads|executive department|federal agency)\b/i.test(x);
  const measurable=/\b(?:\d{4}|\d+(?:\.\d+)?\s*(?:percent|%|million|billion|trillion|days|entries|people|agencies|programs|dollars))\b/i.test(x);
  const promo=/\b(?:most effective and moral|greatest|history of the world|golden age|greatness|prosperity|historic|achievement|success|world leader|global leader|patriotic|national pride|unmistakably|promising|brighter future|opportunity and security ahead|renewed focus|record-setting|surged|solidified)\b/i.test(x);
  const preamble=/\b(?:shall be the policy of the United States|it is the policy of the United States|policy of the United States Government)\b/i.test(c);
  if(complete) score+=100; else score-=110;
  if(concrete) score+=130; else score-=70;
  if(namedAuthority) score+=150;
  if(concreteAction) score+=130;
  if(measurable) score+=70;
  if(/\b(?:President|United States|White House|federal|executive department|agency heads|Secretary|Administrator|Director|National Security)\b/i.test(x)) score+=35;
  if(preamble) score-=115;
  if(promo) score-=220;
  if(promo && !(namedAuthority || concreteAction || measurable)) score-=180;
  if(/^(?:It|This|That|These|Those|They|He|She|We)\b/i.test(c)) score-=95;
  if(/^(?:To|As|By|With|For|Through|During|After|Before|While|When|Since|Because|Although|If|Unless)\b/i.test(c)) score-=105;
  if(/\b(?:be defended to the greatest extent practicable|heads be accountable)\b/i.test(c) && !namedAuthority) score-=95;
  if(/\b(?:shall|must|directed to|ordered to|required to)\b/i.test(c) && namedAuthority) score+=55;
  if(words<9) score-=80;
  if(words>=12 && words<=45) score+=25;
  return score;
}
function topClaimCandidateDiagnostics(normalized, ranked){
  const src=(ranked&&ranked.length?ranked:normalized||[]).slice(0,5).map(o=>clean((o.display||o.claim||'')).replace(/\|/g,'/').slice(0,170));
  return src.join(' ; ') || 'none';
}

function extractRetrievedClaims(title, text, route){
  const all=linkedDestinationFactCandidates(text, route).concat(linkedContentSeedCandidates(text, route)).concat(structuredHomepageContentCandidates(text, route)).concat(completeSentenceAuditCandidates(text, route)).concat(primarySentencePromotionCandidates(text)).concat(recoveredConcreteFactCandidates(text, route));
  let extracted_candidates=all.length;
  extractRetrievedClaims.lastDiagnostics='CLAIM_CANDIDATE_COUNT: '+extracted_candidates+'\nTOP_CLAIM_CANDIDATES: none\nCLAIM_SELECTION_REASON: pending\nACTIVE_CONTENT_SOURCE: claim-extraction\nCONTENT_SOURCE_TYPE: article_claim_candidates';
  let post_normalization_candidates=0;
  let post_filter_candidates=0;
  let post_threshold_candidates=0;
  const normalized=[];
  all.forEach(raw=>{
    let claim=normalizeClaimCandidate(raw);
    if(!claim) return;
    if(route==='url-institutional') claim=parentSentenceRecoveredClaim(text, raw, claim, route);
    claim=normalizeClaimCandidate(claim);
    if(!claim) return;
    if(route==='url-institutional' && isWhiteHouseHomepageFragmentCandidate(claim) && concreteParentRewriteForHomepageFragment(raw+' '+claim)){
      claim=concreteParentRewriteForHomepageFragment(raw+' '+claim);
    }
    const concreteInstitutional=(route==='url-institutional' && hasConcreteVerificationSignal(claim));
    if(!isFactualAssertion(claim) && !concreteInstitutional) return;
    const display=displayClaimTitle(claim,route);
    if(!display) return;
    if(route==='url-institutional' && (isInstitutionalTitleOnlyClaim(raw,route) || isInstitutionalTitleOnlyClaim(claim,route) || isInstitutionalTitleOnlyClaim(display,route))) return;
    if(!isFactualAssertion(display) && !concreteInstitutional) return;
    normalized.push({raw,claim,display});
    post_normalization_candidates=normalized.length;
    post_filter_candidates=normalized.length;
  });
  post_normalization_candidates=normalized.length;
  post_filter_candidates=normalized.length;
  const concreteAvailable=normalized.some(o=>hasConcreteVerificationSignal(o.claim) || hasConcreteVerificationSignal(o.display));
  const ranked=[];
  let ranking_filter_in=normalized.length;
  let ranking_filter_rejected=0;
  normalized.forEach(o=>{
    const raw=o.raw, claim=o.claim, display=o.display;
    if(concreteAvailable && isPromotionalNarrativeSummary(raw+' '+claim+' '+display)){ ranking_filter_rejected += 1; return; }
    if(route==='url-institutional' && isInstitutionalOutcomeNarrative(raw+' '+claim+' '+display) && !/\b(?:tax reforms|deregulation|policy|policies|executive order|proclamation|memorandum|signed|issued|law|program|report|study|statistic)\b/i.test(claim+' '+display)){ ranking_filter_rejected += 1; return; }
    if(route==='url-institutional' && /\b(?:record[- ]setting capital expenditures|capital expenditures driving productivity|productivity and technological advancement|renewed focus on American innovation|solidified its position|global leader)\b/i.test(claim+' '+display)){ ranking_filter_rejected += 1; return; }
    if(isNarrativePreambleCandidate(raw, claim, display, route, concreteAvailable)){ ranking_filter_rejected += 1; return; }
    if(concreteAvailable && !(hasConcreteVerificationSignal(claim) || hasConcreteVerificationSignal(display))){ ranking_filter_rejected += 1; return; }
    const score=claimScore(claim,route)+claimScore(display,route)+independentDeclarativeScore(claim)+sourceStatementPriorityScore(raw,claim,display,route)+factualityRankingScore(raw,claim,display,route)+concreteFactPriorityScore(raw,claim,display,route)+concreteEnforcementScore(raw,claim,display,route,concreteAvailable)+institutionalPromotionalPenalty(raw,claim,display,route)+institutionalActionPriorityScore(raw,claim,display,route,concreteAvailable)+narrativePreambleEliminationScore(raw,claim,display,route,concreteAvailable)+directiveRequirementSelectionScore(raw,claim,display,route,concreteAvailable)+operationalSentenceSelectionScore(raw,claim,display,route,concreteAvailable)+sectionSourceSelectionScore(raw,claim,display,route,concreteAvailable)+structuredHomepagePriorityScore(raw,claim,display,route)+linkedSeedTargetExpansionScore(raw,claim,display,route)+articleClaimExtractionQualityScore(raw,claim,display,route)+Math.min(3,Math.floor(claim.length/90));
    if(score<7){ ranking_filter_rejected += 1; return; }
    post_threshold_candidates += 1;
    if(ranked.some(prev=>nearDuplicate(prev.claim,claim) || nearDuplicate(prev.display,display) || substantiallyContained(prev.claim,claim) || substantiallyContained(prev.display,display))){ ranking_filter_rejected += 1; return; }
    ranked.push({claim,display,score});
  });
  if(route==='url-institutional' && normalized.length>0 && ranked.length===0){
    const rescue=normalized.map(o=>{
      const raw=o.raw, claim=o.claim, display=o.display;
      const score=claimScore(claim,route)+claimScore(display,route)+independentDeclarativeScore(claim)+sourceStatementPriorityScore(raw,claim,display,route)+factualityRankingScore(raw,claim,display,route)+concreteFactPriorityScore(raw,claim,display,route)+concreteEnforcementScore(raw,claim,display,route,concreteAvailable)+institutionalActionPriorityScore(raw,claim,display,route,concreteAvailable)+narrativePreambleEliminationScore(raw,claim,display,route,concreteAvailable)+directiveRequirementSelectionScore(raw,claim,display,route,concreteAvailable)+operationalSentenceSelectionScore(raw,claim,display,route,concreteAvailable)+sectionSourceSelectionScore(raw,claim,display,route,concreteAvailable)+structuredHomepagePriorityScore(raw,claim,display,route)+linkedSeedTargetExpansionScore(raw,claim,display,route)+articleClaimExtractionQualityScore(raw,claim,display,route)+Math.min(3,Math.floor(claim.length/90));
      return {claim,display,score};
    }).filter(o=>hasConcreteVerificationSignal(o.claim) || hasConcreteVerificationSignal(o.display) || isFactualAssertion(o.claim) || isFactualAssertion(o.display));
    rescue.sort((a,b)=>b.score-a.score || a.display.length-b.display.length);
    rescue.forEach(o=>{
      if(ranked.some(prev=>nearDuplicate(prev.claim,o.claim) || nearDuplicate(prev.display,o.display) || substantiallyContained(prev.claim,o.claim) || substantiallyContained(prev.display,o.display))) return;
      ranked.push(o);
    });
  }
  ranked.sort((a,b)=>b.score-a.score || a.display.length-b.display.length);
  const final=[];
  ranked.forEach(o=>{
    if(final.some(f=>nearDuplicate(f.display,o.display) || substantiallyContained(f.claim,o.claim) || substantiallyContained(f.display,o.display))) return;
    final.push(o);
  });
  extractRetrievedClaims.lastDiagnostics='CLAIM_CANDIDATE_COUNT: '+extracted_candidates+'\nTOP_CLAIM_CANDIDATES: '+topClaimCandidateDiagnostics(normalized, final.length?final:ranked)+'\nCLAIM_SELECTION_REASON: implementation/responsibility/directive sections prioritized over policy/purpose/rationale sections\nCLAIM_SECTION_SOURCE: '+(final[0]?claimSectionSourceLabel('',final[0].claim,final[0].display,route):'none')+'\nSECTION_SELECTION_REASON: implementation, responsibilities, directives, requirements, reporting, compliance, execution, deadlines, and agency-action sections preferred when present\nACTIVE_CONTENT_SOURCE: child-article-followthrough\nCONTENT_SOURCE_TYPE: child_article_body';
  return final.slice(0,3);
}
function contradictionScan(text, route){
  const s=clean(text).toLowerCase();
  const flags=[];
  if(/retract|correction|false|hoax|misleading|debunk|not true|no evidence|unsupported/.test(s)) flags.push('contradiction language present in retrieved page text');
  if(route==='url-science' && /conspiracy|alien structures|time traveler|flat earth/.test(s)) flags.push('extraordinary wording detected on a science-routed source');
  return flags;
}
function claimContainsDirectContradiction(claim){
  const s=clean(claim).toLowerCase();
  return /\b(?:false|hoax|misleading|debunked|unsupported|not true|no evidence|contradicts|retracted|correction)\b/.test(s);
}
function urlClaimIsDirectSourceFact(route, claim, page){
  if(!/^url-/.test(route)) return false;
  const c=clean(claim);
  const pageText=clean(page&&page.text||'');
  if(!c || !pageText) return false;
  const root=claimRootKey(c).slice(0,120);
  const pageRoot=claimRootKey(pageText);
  if(root && root.length>=35 && pageRoot.includes(root)) return true;
  return overlapRatio(c,pageText)>=0.62;
}
function corroborationLine(route, page){
  if(route==='url-science') return 'Official NASA/government science source retrieved; page content is treated as primary source material for claims made by that page.';
  if(route==='url-health') return 'Official CDC/public-health source retrieved; page content is treated as primary source material for claims made by that page.';
  if(route==='url-institutional') return 'Official White House/government source retrieved; page content is treated as primary source material for claims made by that page.';
  return 'Live page source retrieved; claim support depends on the page content and source identity.';
}
function verdictFor(route, claim, contradictions, page){
  const directSourceFact=urlClaimIsDirectSourceFact(route, claim, page);
  if(contradictions.length && claimContainsDirectContradiction(claim)) return {status:'MIXED / REVIEW NEEDED', verdict:'Retrieved page content contains contradiction language tied to this claim, so it needs closer review before being treated as verified.', reliability:'Partial support / contradiction review needed'};
  if(route==='url-science') return {status:'SOURCE SUPPORTED', verdict:'The retrieved NASA page directly supports this page-derived claim as official science-source material.', reliability:directSourceFact?'High confidence':'Source retrieved / authority high'};
  if(route==='url-health') return {status:'SOURCE SUPPORTED', verdict:'The retrieved CDC page directly supports this page-derived claim as official public-health source material.', reliability:directSourceFact?'High confidence':'Source retrieved / health authority high'};
  if(route==='url-institutional') return {status:'SOURCE SUPPORTED', verdict:'The retrieved White House page directly supports this page-derived claim as official institutional source material.', reliability:directSourceFact?'High confidence':'Source retrieved / institutional authority high'};
  if(contradictions.length) return {status:'MIXED / REVIEW NEEDED', verdict:'Retrieved page content contains possible contradiction language, so this claim needs closer review before being treated as verified.', reliability:'Partial support / contradiction review needed'};
  return {status:'SOURCE REVIEWED', verdict:'The retrieved page content supplies source material for this page-derived claim; independent corroboration may still be needed for stronger verification.', reliability:'Source retrieved / review required'};
}
function urlKind(route){
  if(route==='url-science') return 'URL / SCIENCE SOURCE';
  if(route==='url-health') return 'URL / HEALTH SOURCE';
  if(route==='url-institutional') return 'URL / INSTITUTIONAL SOURCE';
  return 'URL SOURCE';
}
function keyFor(route, i){
  if(route==='url-science') return 'url_science_page_claim_'+i;
  if(route==='url-health') return 'url_health_page_claim_'+i;
  if(route==='url-institutional') return 'url_institutional_page_claim_'+i;
  return 'url_page_claim_'+i;
}

