    technicalBasis: technicalBasis,
    limitations: limitations,
    factualAccuracyAnalysis: factual,
    factualDetectedTopic: mainClaim || '',
    factualAutoResult: factualAutoResult || null,
    factualAnalysisStatus: factualAutoResult ? (musicTargetDetected ? 'music-video-detection-only' : 'auto-analyzed') : (musicVideoWithoutSpecificClaim ? 'music-video-detection-only' : 'need-topic-or-claim'),
    musicVideoWithoutSpecificClaim:musicTargetDetected?true:musicVideoWithoutSpecificClaim,
    musicTargetDetected:musicTargetDetected,
    musicAnalysisReady:false,
    musicInputType:musicTargetDetected ? (info.isUrl ? 'music-video-song-url-detection-only' : 'music-video-song-reference-detection-only') : 'not-music-no-claim-gate',
