    return ['Backend: '+VERSION+' | yt:false | src:structured | route:question-factual',...requestAuditLines(primary),...analysisBindingAuditLines(),...ai(primary),'Question Normalized Claim: '+normalizedMoonLandingClaim,'ClaimKey: '+normalizedMoonLandingClaim+' | Subject: '+normalizedMoonLandingClaim+' | Status: ACCURATE | Classification: QUESTION / HISTORICAL FACTUAL','ClaimText: '+normalizedMoonLandingClaim,"FINAL VERDICT: NASA's Apollo 11 mission landed astronauts on the Moon in 1969.",'Summary: NASA\'s Apollo 11 mission landed astronauts on the Moon in 1969.','Confidence: HIGHEST | ConfidenceScore: 95/100','Evidence: The Apollo 11 mission records from NASA identify Neil Armstrong and Buzz Aldrin as landing on the Moon on July 20, 1969, while Michael Collins remained in lunar orbit.','Sources: NASA Apollo 11 mission history','Source URL: https://www.nasa.gov/history/apollo-11-mission-overview/','Supporting Information: Apollo 11 landed on the Moon on July 20, 1969; Neil Armstrong and Buzz Aldrin walked on the lunar surface; Apollo 11 returned lunar rock and soil samples to Earth.','Overall Reliability Score: 95%', d].filter(Boolean).join('\n');
