function v2712OpenAIRequest(payload,timeoutMs){
  return new Promise(function(resolve){
    const key=process.env.OPENAI_API_KEY || '';
    if(!key){
      return resolve({
        ok:false,
        statusCode:0,
        errorType:'missing_openai_api_key',
        errorCode:'',
        json:null
      });
    }

    const body=JSON.stringify(payload||{});
    let settled=false;

    function finish(value){
      if(settled) return;
      settled=true;
      resolve(value);
    }

    const req=https.request({
      hostname:'api.openai.com',
      port:443,
      path:'/v1/responses',
      method:'POST',
      headers:{
        'content-type':'application/json',
        'authorization':'Bearer '+key,
        'content-length':Buffer.byteLength(body)
      }
    },function(res){
      let data='';
      res.setEncoding('utf8');
      res.on('data',function(chunk){
        data+=chunk;
        if(data.length>4*1024*1024){
          req.destroy(new Error('openai_response_too_large'));
        }
      });
      res.on('end',function(){
        const json=safeJsonParse(data);
        if(res.statusCode>=200 && res.statusCode<300 && json){
          return finish({
            ok:true,
            statusCode:res.statusCode,
            errorType:'',
            errorCode:'',
            json:json
          });
        }

        const err=json && json.error && typeof json.error==='object' ? json.error : {};
        return finish({
          ok:false,
          statusCode:res.statusCode||0,
          errorType:clean(err.type)||('http_'+String(res.statusCode||0)),
          errorCode:clean(err.code),
          json:json
        });
      });
    });

    req.on('error',function(error){
      finish({
        ok:false,
        statusCode:0,
        errorType:error && error.message ? String(error.message).slice(0,80) : 'request_error',
        errorCode:'',
        json:null
      });
    });

    req.setTimeout(timeoutMs,function(){
      req.destroy(new Error('timeout'));
    });

    req.write(body);
    req.end();
  });
}

function v2712ExtractOutputText(json){
  if(!json) return '';

  const pieces=[];
  const seen=new Set();

  function add(value){
    if(value==null) return;
    if(Array.isArray(value)){
      value.forEach(add);
      return;
    }
    if(typeof value==='object'){
      if(typeof value.value==='string') add(value.value);
      return;
    }
    const s=String(value).trim();
    if(!s || seen.has(s)) return;
    seen.add(s);
    pieces.push(s);
  }

  add(json.output_text);

  (json.output||[]).forEach(function(item){
    if(!item) return;
    add(item.text);
    add(item.output_text);
    (item.content||[]).forEach(function(content){
      if(!content) return;
      add(content.text);
      add(content.output_text);
      add(content.value);
      if(content.type==='output_text') add(content.text);
    });
  });

  if(json.response && typeof json.response==='object'){
    add(json.response.output_text);
    add(json.response.text);
  }

  if(Array.isArray(json.choices)){
    json.choices.forEach(function(choice){
      if(choice && choice.message) add(choice.message.content);
      if(choice) add(choice.text);
    });
  }

  return pieces.join('\n').trim();
}

function v2712ExtractBalancedJson(text){
  const s=String(text||'')
    .trim()
    .replace(/^```(?:json)?\s*/i,'')
    .replace(/\s*```$/,'')
    .trim();

  if(!s) return null;

  let parsed=safeJsonParse(s);
  if(parsed) return parsed;

  let start=-1;
  let depth=0;
  let inString=false;
  let escaped=false;

  for(let i=0;i<s.length;i++){
    const ch=s[i];

    if(inString){
      if(escaped){
        escaped=false;
      }else if(ch==='\\'){
        escaped=true;
      }else if(ch==='"'){
        inString=false;
      }
      continue;
    }

    if(ch==='"'){
      inString=true;
      continue;
    }

    if(ch==='{'){
      if(start<0) start=i;
      depth++;
      continue;
    }

    if(ch==='}' && start>=0){
      depth--;
      if(depth===0){
        parsed=safeJsonParse(s.slice(start,i+1));
        if(parsed) return parsed;
        start=-1;
      }
    }
  }

  return null;
}

function v2712NormalizeEvaluatorObject(value){
  if(!value || typeof value!=='object') return null;

  let root=value;
  ['result','data','response','evaluation','output'].some(function(key){
    if(root[key] && typeof root[key]==='object' && !Array.isArray(root[key])){
      root=root[key];
      return true;
    }
    return false;
  });

  const normalized=v2711NormalizeEvaluatorObject(root);
  if(!normalized) return null;

  const hasUsableQuestionAnswer=clean(normalized.answer) || normalized.answerList.length;
  const hasUsableClaimVerdict=clean(normalized.verdict);

  if(!hasUsableQuestionAnswer && !hasUsableClaimVerdict) return null;
  return normalized;
}

