function v2801Profile(raw){
  return v2801FaithProfile(raw)||v2801GeneralProfile(raw);
}

function v2801RemoveInternalClassificationWording(value){
  const raw=clean(value);
  if(!raw)return '';
  return splitSentences(raw).filter(function(sentence){
    const s=clean(sentence);
    return s&&!/\b(?:general advice\/how-to question|stable factual claim|classification|output basket|evaluator|routing decision|route selected|concise checklist helps determine legitimacy without needing live verification)\b/i.test(s);
  }).map(v2771Sentence).join(' ');
}

function v2801ApplyTransparentSourcePolicy(contract,input){
  const c=contract&&typeof contract==='object'?contract:{};
  const raw=clean(input);
  const faith=v2788FaithContract(c);
  const submittedUrl=/^https?:\/\/\S+$/i.test(raw)?validHttpUrl(raw):'';
  const sourceUrl=validHttpUrl(c.sourceUrl||c.primarySourceUrl||'');

  c.hideSourceBasis=true;
  c.suppressSourceBasis=true;
  c.showSource=false;
  c.suppressDuplicateSubmittedSource=false;

  if(faith){
    c.source=clean(c.source||'Biblical Scriptures');
    c.sourceBasis=c.source;
    c.sourceDisplayPolicy='SCRIPTURE_REFERENCES_ARE_SOURCE';
    c.showSourceUrl=false;
    return c;
  }

  if(submittedUrl){
    c.sourceDisplayPolicy='SUBMITTED_URL_IS_SOURCE';
    if(sourceUrl&&sourceUrl===submittedUrl){
      c.suppressDuplicateSubmittedSource=true;
      c.showSourceUrl=false;
    }else{
      c.showSourceUrl=!!sourceUrl;
    }
    return c;
  }

  if(sourceUrl){
    c.sourceUrl=sourceUrl;
    c.primarySourceUrl=sourceUrl;
    c.showSourceUrl=true;
    c.showSource=true;
    c.sourceDisplayPolicy='SHOW_EXTERNAL_SOURCE';
    return c;
  }

  c.source='OpenAI model knowledge';
  c.sourceBasis='OpenAI model knowledge';
  c.sourceUrl='';
  c.primarySourceUrl='';
  c.showSourceUrl=false;
  c.showSource=true;
  c.sourceDisplayPolicy='SHOW_MODEL_KNOWLEDGE';
  if(c.technicalDiagnostics&&typeof c.technicalDiagnostics==='object'){
    c.technicalDiagnostics.sourceRetrievalPerformed='NO';
    c.technicalDiagnostics.sourceProvenance='OPENAI_MODEL_KNOWLEDGE';
  }
  return c;
}

function v2801ReapplyProfileContract(contract,input,profile){
  let c=contract&&typeof contract==='object'?contract:{};
  if(!profile||!profile.facts)return c;
  const desired=v2771RenderControlledContract(input,profile.facts);
  const copyKeys=['route','claim','pageTitle','pageSummary','summary','answer','answerList','why','explanation','evidence','supportingInformation','source','sourceBasis','sourceUrl','primarySourceUrl','confidence','uncertainty','classification','status','inputType','outputBasket','fixedOutputBasket','displayLabels'];
  copyKeys.forEach(function(key){
    if(Object.prototype.hasOwnProperty.call(desired,key)) c[key]=JSON.parse(JSON.stringify(desired[key]));
  });
  c.analysisResult='Answer';
  c.minimalDirectAnswer=false;
  c.suppressExplanation=false;
  c.explanationDisplayPolicy='ANSWER_EXPLANATION_AND_SOURCE';
  if(profile.claimVerdict){
    c.inputType='CLAIM';
    c.analysisResult=profile.claimVerdict;
    c.status='EVALUATED';
    c.displayLabels={claim:'Claim',answer:'Analysis Result'};
  }
  c.why=v2801RemoveInternalClassificationWording(c.why||c.explanation||'');
  c.explanation=c.why;
  c.summary=clean(c.summary||c.why||c.answer);
  if(v2788FaithContract(c)){
    c.supportingInformation=v2788AddMaterialKjvDefinitions(c.supportingInformation||'');
    c.additionalInformationLayout='EXPLANATION_SUPPORT_CONFIDENCE_DEFINITIONS';
  }
  v2780RemoveOrphanDefinitionMarkers(c);
  v2801ApplyTransparentSourcePolicy(c,input);
  v2774StampCurrentContract(c,input);
  c.validationErrors=v2771ContractValidationErrors(c,input);
  c.contractValidated=c.validationErrors.length===0;
  c.technicalDiagnostics=Object.assign({},c.technicalDiagnostics||{}, {
    activeFunction:'r1BetaProfileReapplicationV2801',
    profileReappliedAfterLegacyFinalizers:'YES',
    transparentSourcePolicy:c.sourceDisplayPolicy,
    validationState:c.contractValidated?'PASS':'FAIL',
    validationErrors:c.validationErrors.join(',')||'NONE'
  });
  return c;
}

function v2801FinalizeImmutableContract(contract,input){
  let c=contract&&typeof contract==='object'?JSON.parse(JSON.stringify(contract)):{};
  const profile=v2801Profile(input);
  if(profile&&profile.facts) return v2801ReapplyProfileContract(c,input,profile);
  c.why=v2801RemoveInternalClassificationWording(c.why||c.explanation||'');
  c.explanation=c.why;
  if(clean(c.summary)&&/\b(?:general advice\/how-to question|stable factual claim|classification|output basket|evaluator|routing decision)\b/i.test(clean(c.summary))){
    c.summary=c.why||clean(c.answer);
  }
  v2801ApplyTransparentSourcePolicy(c,input);
  v2800ApplyPublicDirectAnswerPolicy(c,input);
  v2774StampCurrentContract(c,input);
  c.validationErrors=v2771ContractValidationErrors(c,input);
  c.contractValidated=c.validationErrors.length===0;
  c.technicalDiagnostics=Object.assign({},c.technicalDiagnostics||{}, {
    activeFunction:'r1BetaImmutableBoundaryRepairV2801',
    immutableSourcePolicyRestored:c.sourceDisplayPolicy,
    validationState:c.contractValidated?'PASS':'FAIL',
    validationErrors:c.validationErrors.join(',')||'NONE'
  });
  return c;
}

function v2801FinalizeContract(contract,input){
  let c=v2800FinalizeContract(contract,input);
  const cleaned=v2801RemoveInternalClassificationWording(c.why||c.explanation||'');
  c.why=cleaned;
  c.explanation=cleaned;
  if(clean(c.summary)&&/\b(?:general advice\/how-to question|stable factual claim|classification|output basket|evaluator|routing decision)\b/i.test(clean(c.summary))){
    c.summary=cleaned||clean(c.answer);
  }
  v2801ApplyTransparentSourcePolicy(c,input);
  v2780RemoveOrphanDefinitionMarkers(c);
  v2783RemoveNeutralTechnologyFaithContamination(c,input);
  v2774StampCurrentContract(c,input);
  c.validationErrors=v2771ContractValidationErrors(c,input);
  c.contractValidated=c.validationErrors.length===0;
  c.technicalDiagnostics=Object.assign({},c.technicalDiagnostics||{},{
    activeFunction:'r1BetaAnswerabilitySourceGuidanceAndPublicSampleRepairV2801',
    transparentSourcePolicy:c.sourceDisplayPolicy,
    internalClassificationWording:'REMOVED',
    validationState:c.contractValidated?'PASS':'FAIL',
    validationErrors:c.validationErrors.join(',')||'NONE'
  });
  return c;
}



