    if(cacheEligible&&!isAborted()&&bound&&v2838RawResponseCacheEligible(immutable))v2764StoreCompletedContract(key,normalizedInput,immutable,input);
    return v2764AttachCacheTrace(immutable,'MISS',keyId,false);
